import React from 'react';
import { PageConfig } from '../../types';

interface PageTabsProps {
    pages: PageConfig[];
    activePageId: string;
    onPageSelect: (pageId: string) => void;
    onPageAdd: () => void;
    onPageRename: (pageId: string, newName: string) => void;
    onPageDelete: (pageId: string) => void;
}

const PageTabs: React.FC<PageTabsProps> = ({
    pages,
    activePageId,
    onPageSelect,
    onPageAdd,
    onPageRename,
    onPageDelete
}) => {
    const [editingPageId, setEditingPageId] = React.useState<string | null>(null);
    const [editingName, setEditingName] = React.useState<string>('');

    const handleRename = (pageId: string, currentName: string) => {
        setEditingPageId(pageId);
        setEditingName(currentName);
    };

    const handleRenameSubmit = (pageId: string) => {
        if (editingName.trim()) {
            onPageRename(pageId, editingName.trim());
        }
        setEditingPageId(null);
        setEditingName('');
    };

    const handleRenameCancel = () => {
        setEditingPageId(null);
        setEditingName('');
    };

    return (
        <div style={{
            display: 'flex',
            alignItems: 'center',
            backgroundColor: '#f8f9fa',
            borderBottom: '1px solid #dee2e6',
            padding: '0 20px',
            minHeight: '45px',
            overflowX: 'auto',
            whiteSpace: 'nowrap'
        }}>
            {pages.map((page) => (
                <div
                    key={page.id}
                    style={{
                        display: 'inline-flex',
                        alignItems: 'center',
                        backgroundColor: page.id === activePageId ? '#ffffff' : 'transparent',
                        border: page.id === activePageId ? '1px solid #dee2e6' : '1px solid transparent',
                        borderBottom: page.id === activePageId ? '1px solid #ffffff' : '1px solid transparent',
                        borderRadius: '8px 8px 0 0',
                        padding: '8px 12px',
                        margin: '0 2px',
                        cursor: 'pointer',
                        position: 'relative',
                        minWidth: '120px',
                        maxWidth: '200px',
                        fontSize: '14px',
                        fontWeight: page.id === activePageId ? '600' : '400',
                        color: page.id === activePageId ? '#495057' : '#6c757d',
                        transition: 'all 0.2s ease',
                        userSelect: 'none'
                    }}
                    onClick={() => onPageSelect(page.id)}
                    onDoubleClick={() => handleRename(page.id, page.name)}
                >
                    {editingPageId === page.id ? (
                        <input
                            type="text"
                            value={editingName}
                            onChange={(e) => setEditingName(e.target.value)}
                            onBlur={() => handleRenameSubmit(page.id)}
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                    handleRenameSubmit(page.id);
                                } else if (e.key === 'Escape') {
                                    handleRenameCancel();
                                }
                            }}
                            style={{
                                border: 'none',
                                outline: 'none',
                                background: 'transparent',
                                fontSize: '14px',
                                fontWeight: '600',
                                color: '#495057',
                                width: '100%'
                            }}
                            autoFocus
                            onClick={(e) => e.stopPropagation()}
                        />
                    ) : (
                        <>
                            <span style={{
                                overflow: 'hidden',
                                textOverflow: 'ellipsis',
                                whiteSpace: 'nowrap',
                                flex: 1
                            }}>
                                {page.name}
                            </span>
                            {pages.length > 1 && (
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onPageDelete(page.id);
                                    }}
                                    style={{
                                        marginLeft: '8px',
                                        background: 'none',
                                        border: 'none',
                                        color: '#6c757d',
                                        cursor: 'pointer',
                                        fontSize: '12px',
                                        padding: '2px',
                                        borderRadius: '50%',
                                        width: '16px',
                                        height: '16px',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        opacity: 0.7,
                                        transition: 'all 0.2s ease'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.currentTarget.style.backgroundColor = '#dc3545';
                                        e.currentTarget.style.color = '#ffffff';
                                        e.currentTarget.style.opacity = '1';
                                    }}
                                    onMouseLeave={(e) => {
                                        e.currentTarget.style.backgroundColor = 'transparent';
                                        e.currentTarget.style.color = '#6c757d';
                                        e.currentTarget.style.opacity = '0.7';
                                    }}
                                    title="Close page"
                                >
                                    ×
                                </button>
                            )}
                        </>
                    )}
                </div>
            ))}
            
            {/* Add New Page Button */}
            <button
                onClick={onPageAdd}
                style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    backgroundColor: 'transparent',
                    border: '1px solid #dee2e6',
                    borderRadius: '6px',
                    padding: '6px 10px',
                    margin: '0 4px',
                    cursor: 'pointer',
                    fontSize: '14px',
                    color: '#6c757d',
                    transition: 'all 0.2s ease',
                    minWidth: '32px',
                    height: '32px'
                }}
                onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#e9ecef';
                    e.currentTarget.style.borderColor = '#adb5bd';
                }}
                onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'transparent';
                    e.currentTarget.style.borderColor = '#dee2e6';
                }}
                title="Add new page"
            >
                +
            </button>
        </div>
    );
};

export default PageTabs;
